-- examples/fix_examples.lua
local dnadesign = require("dnadesign")
local fix = dnadesign.fix
local codon = dnadesign.codon

describe("Fix Examples", function()
    it("demonstrates basic usage", function()
        -- Initialize a gene. We will be using bla, or ampicillin resistance.
        local bla = ""
        
        -- Use the pichia codon table
        local pichia_table = codon.default_tables["pichia"]
        
        -- Fix the sequence with cds_simple, removing BsaI site (GGTCTC)
        local fixed_seq, _, _ = fix.cds_simple(bla, pichia_table, {"GGTCTC"})
        
        -- The sequence should be fixed and BsaI site removed
        assert.is_truthy(fixed_seq)
        assert.is_nil(string.find(fixed_seq, "GGTCTC"))
    end)

    it("demonstrates using cds directly", function()
        local bla = ""
        
        -- Use the pichia codon table
        local pichia_table = codon.default_tables["pichia"]
        
        -- Create problem finder functions
        local functions = {
            fix.remove_repeat(20),
            fix.remove_sequence(
                {"GAAGAC", "GGTCTC", "GCGATG", "CGTCTC", "GCTCTTC", "CACCTGC"},
                "TypeIIS restriction enzyme site"
            )
        }
        
        -- Fix sequence and get changes
        local fixed_seq, changes, _ = fix.cds(bla, pichia_table, functions)
        
        -- Check a specific change (similar to Go example)
		for i, change in ipairs(changes) do
			if change.position == 248 then
				assert.are.equal(248, change.position)
        		assert.are.equal("CGC", change.from)
        		assert.are.equal("AGA", change.to)
        		assert.are.equal("TypeIIS restriction enzyme site", change.reason)
			end
		end
    end)

    it("demonstrates using cds_simple with homopolymers", function()
        local bla = ""
        
        -- Use the pichia codon table
        local pichia_table = codon.default_tables["pichia"]
        
        -- Fix sequence and get changes
        local fixed_seq, changes, _ = fix.cds_simple(bla, pichia_table, {"GGTCTC"})
        
        -- Check the first change (homopolymer fix)
		for i, change in ipairs(changes) do
			if change.position == 2 then
        		assert.are.equal(2, change.position)
        		assert.are.equal("AAA", change.from)
        		assert.are.equal("AAG", change.to)
        		assert.are.equal("Homopolymers", change.reason)
			end
		end
    end)
end)
